class Transaction:
 def __init__(self, version=1, locktime=0):
 self.version = version
 self.inputs = []
 self.outputs = []
 self.locktime = locktime

 def add_input(self, input):
 self.inputs.append(input)

 def add_output(self, output):
 self.outputs.append(output)

 def calculate_fee(self):
 input_sum = sum(input.value for input in self.inputs)
 output_sum = sum(output.value for output in self.outputs)
 return input_sum - output_sum

 def __str__(self):
 return f'Transaction(version={self.version}, inputs={self.inputs}, outputs={self.outputs}, locktime={self.locktime})'

#include <stdio.h>
#include <stdlib.h>

typedef struct {
 int version;
 struct Input* inputs;
 int input_count;
 struct Output* outputs;
 int output_count;
 int locktime;
} Transaction;

void add_input(Transaction* transaction, struct Input* input) {
 transaction->inputs = realloc(transaction->inputs, (transaction->input_count + 1) * sizeof(struct Input));
 transaction->inputs[transaction->input_count] = *input;
 transaction->input_count++;
}

void add_output(Transaction* transaction, struct Output* output) {
 transaction->outputs = realloc(transaction->outputs, (transaction->output_count + 1) * sizeof(struct Output));
 transaction->outputs[transaction->output_count] = *output;
 transaction->output_count++;
}

int calculate_fee(Transaction* transaction) {
 int input_sum = 0;
 for (int i = 0; i < transaction->input_count; i++) {
 input_sum += transaction->inputs[i].value;
 }
 int output_sum = 0;
 for (int i = 0; i < transaction->output_count; i++) {
 output_sum += transaction->outputs[i].value;
 }
 return input_sum - output_sum;
}
